-- 600???????????
SET NAMES utf8mb4;
SET @school_id = 1;
SET @grade_name = '高一';
SET @event_name = '2026高一600人抽签测试活动';
SET @student_prefix = 'CS26%';

SELECT @grade_name, @school_id
FROM dual
WHERE NOT EXISTS (
  SELECT 1 FROM grades g WHERE g.school_id = @school_id AND g.name = @grade_name
);

DROP TEMPORARY TABLE IF EXISTS tmp_class_seed;
CREATE TEMPORARY TABLE tmp_class_seed (
  class_name VARCHAR(100) NOT NULL,
  class_type VARCHAR(20) NOT NULL,
  grade_name VARCHAR(50) NOT NULL
);

SELECT t.class_name, g.id, NULL, t.class_type, @school_id
FROM tmp_class_seed t
JOIN grades g ON g.school_id = @school_id AND g.name = t.grade_name
LEFT JOIN classes c ON c.school_id = @school_id AND c.name = t.class_name AND c.type = t.class_type AND c.grade_id = g.id
WHERE c.id IS NULL;

DROP TEMPORARY TABLE IF EXISTS tmp_student_seed;
CREATE TEMPORARY TABLE tmp_student_seed (
  grade_name VARCHAR(50) NOT NULL,
  class_name VARCHAR(100) NOT NULL,
  student_name VARCHAR(50) NOT NULL,
  gender VARCHAR(10),
  student_no VARCHAR(50) NOT NULL,
  id_card VARCHAR(20),
  elective_class VARCHAR(100),
  student_status VARCHAR(20)
);

SELECT t.student_name, t.gender, t.student_no, t.id_card, NULLIF(t.elective_class, ''), t.student_status,
       c.id, @school_id, b'1', NULL, 0
FROM tmp_student_seed t
JOIN grades g ON g.school_id = @school_id AND g.name = t.grade_name
JOIN classes c ON c.school_id = @school_id AND c.grade_id = g.id AND c.name = t.class_name AND c.type = '行政班'
ON DUPLICATE KEY UPDATE
  name = VALUES(name),
  gender = VALUES(gender),
  id_card = VALUES(id_card),
  elective_class = VALUES(elective_class),
  student_status = VALUES(student_status),
  class_id = VALUES(class_id),
  school_id = VALUES(school_id);

SELECT @school_id, @event_name,
       '2026-04-01 08:00:00', '2026-04-03 18:00:00',
       '2026-04-04 08:00:00', '2026-04-06 18:00:00',
       'ROUND1', NULL, NOW()
FROM dual
WHERE NOT EXISTS (
  SELECT 1 FROM selection_events e WHERE e.school_id = @school_id AND e.name = @event_name
);

SET @event_id = (
  SELECT e.id FROM selection_events e
  WHERE e.school_id = @school_id AND e.name = @event_name
  ORDER BY e.id DESC LIMIT 1
);

DELETE FROM course_selections WHERE event_id = @event_id;
DELETE FROM event_students WHERE event_id = @event_id;
DELETE cap FROM course_class_capacities cap JOIN courses c ON c.id = cap.course_id WHERE c.event_id = @event_id;
DELETE FROM courses WHERE event_id = @event_id;

UPDATE selection_events
SET round1_start = '2026-04-01 08:00:00',
    round1_end = '2026-04-03 18:00:00',
    round2_start = '2026-04-04 08:00:00',
    round2_end = '2026-04-06 18:00:00',
    status = 'ROUND1',
    lottery_note = NULL,
    created_at = NOW()
WHERE id = @event_id;

DROP TEMPORARY TABLE IF EXISTS tmp_course_seed;
CREATE TEMPORARY TABLE tmp_course_seed (
  course_name VARCHAR(100) NOT NULL,
  capacity_mode VARCHAR(20) NOT NULL,
  total_capacity INT NOT NULL
);

SELECT @event_id, @school_id, t.course_name, CONCAT('600??????? - ', t.course_name), NULL,
       t.capacity_mode, t.total_capacity, 0, 'ACTIVE'
FROM tmp_course_seed t;

SELECT @event_id, s.id
FROM students s
WHERE s.school_id = @school_id
  AND s.student_no LIKE @student_prefix;

SELECT c.id, sc.id, 4, 0
FROM courses c
JOIN classes sc ON sc.school_id = @school_id
JOIN grades g ON g.id = sc.grade_id
WHERE c.event_id = @event_id
  AND c.name IN ('田径提升', '跳绳挑战')
  AND sc.type = '行政班'
  AND g.name = @grade_name
  AND sc.name IN ('1班', '2班', '3班', '4班', '5班', '6班', '7班', '8班', '9班', '10班', '11班', '12班');

DROP TEMPORARY TABLE IF EXISTS tmp_course_selection_seed;
CREATE TEMPORARY TABLE tmp_course_selection_seed (
  student_no VARCHAR(50) NOT NULL,
  course_name VARCHAR(100) NOT NULL,
  preference_no INT NOT NULL,
  selected_at DATETIME NOT NULL
);

SELECT @event_id, c.id, s.id, t.preference_no, 1, 'PENDING', t.selected_at, NULL
FROM tmp_course_selection_seed t
JOIN students s ON s.school_id = @school_id AND s.student_no = t.student_no
JOIN courses c ON c.event_id = @event_id AND c.name = t.course_name;
